class Solution:
    def isSelfCrossing(self, distance) -> bool:
        dirs = [(0, 1), (-1, 0), (0, -1), (1, 0)]
        x = y = 0
        pts = [(0, 0)]
        for i, d in enumerate(distance):
            dx, dy = dirs[i % 4]
            x += dx * d
            y += dy * d
            pts.append((x, y))
        segs = [(pts[i], pts[i + 1]) for i in range(len(pts) - 1)]
        def on(p, a, b):
            return min(a[0], b[0]) <= p[0] <= max(a[0], b[0]) and min(a[1], b[1]) <= p[1] <= max(a[1], b[1])
        def cross(s1, s2):
            (ax, ay), (bx, by) = s1
            (cx, cy), (dx, dy) = s2
            def orient(o, a, b):
                v = (a[0] - o[0]) * (b[1] - o[1]) - (a[1] - o[1]) * (b[0] - o[0])
                return (v > 0) - (v < 0)
            o1 = orient(s1[0], s1[1], s2[0])
            o2 = orient(s1[0], s1[1], s2[1])
            o3 = orient(s2[0], s2[1], s1[0])
            o4 = orient(s2[0], s2[1], s1[1])
            if o1 != o2 and o3 != o4:
                return True
            if o1 == 0 and on(s2[0], s1[0], s1[1]):
                return True
            if o2 == 0 and on(s2[1], s1[0], s1[1]):
                return True
            if o3 == 0 and on(s1[0], s2[0], s2[1]):
                return True
            if o4 == 0 and on(s1[1], s2[0], s2[1]):
                return True
            return False
        for i in range(len(segs)):
            for j in range(i + 2, len(segs)):
                if i == 0 and j == len(segs) - 1:
                    pass
                if cross(segs[i], segs[j]):
                    return True
        return False

